#include <stdio.h>
#include <math.h>
#define MOD 1000000007LL

long long modpow(long long a,long long e){long long r=1%MOD;while(e){if(e&1)r=r*a%MOD;a=a*a%MOD;e>>=1;}return r;}

long long nCr(int n,int r){if(r<0||r>n)return 0;static long long *fact=NULL,*invfact=NULL;static int maxN=0;if(n>maxN){int newN=n;fact=(long long*)realloc(fact,(newN+1)*sizeof(long long));invfact=(long long*)realloc(invfact,(newN+1)*sizeof(long long));fact[0]=1;for(int i=1;i<=newN;i++)fact[i]=fact[i-1]*i%MOD;invfact[newN]=modpow(fact[newN],MOD-2);for(int i=newN;i>0;i--)invfact[i-1]=invfact[i]*i%MOD;maxN=newN;}
return fact[n]*invfact[r]%MOD*invfact[n-r]%MOD;}

void rowCol(long long x,int *row,int *col){ // smallest r with r*(r+1)/2 >= x
    long long r = (long long)(ceil((sqrt(8.0*x+1)-1)/2));
    long long prev = r*(r-1)/2; // T_{r-1}
    *row = (int)r;
    *col = (int)(x - prev);
}

int main(){int T; if(scanf("%d",&T)!=1) return 0; while(T--){ long long s,e; scanf("%lld %lld",&s,&e); int rs,cs,re,ce; rowCol(s,&rs,&cs); rowCol(e,&re,&ce); if(re<rs){ printf("0\n"); continue; }
    int k = re - rs; int d = ce - cs; if(d<0||d>k){ printf("0\n"); continue; }
    printf("%lld\n", nCr(k,d)); }
    return 0; }

