import java.io.*;
import java.util.*;

public class Main {
    static final long MOD = 1_000_000_007L;
    static long modPow(long a,long e){ long long r=1%MOD; while(e>0){ if((e&1)==1) r=r*a%MOD; a=a*a%MOD; e>>=1; } return r; }
    static long[] fact, invFact;
    static long nCr(int n,int r){ if(r<0||r>n) return 0; return fact[n]*invFact[r]%MOD*invFact[n-r]%MOD; }
    static int[] rowCol(long x){ long r = (long)Math.ceil((Math.sqrt(8.0*x+1)-1)/2); long prev = r*(r-1)/2; int row = (int)r; int col = (int)(x - prev); return new int[]{row,col}; }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        int MAXN = 50000;
        fact = new long[MAXN+1]; invFact = new long[MAXN+1];
        fact[0]=1; for(int i=1;i<=MAXN;i++) fact[i]=fact[i-1]*i%MOD;
        invFact[MAXN]=modPow(fact[MAXN], MOD-2);
        for(int i=MAXN;i>0;i--) invFact[i-1]=invFact[i]*i%MOD;
        StringBuilder sb = new StringBuilder();
        for(int t=0;t<T;t++){
            StringTokenizer st = new StringTokenizer(br.readLine());
            long s = Long.parseLong(st.nextToken());
            long e = Long.parseLong(st.nextToken());
            int[] rcS = rowCol(s);
            int[] rcE = rowCol(e);
            int rs = rcS[0], cs = rcS[1];
            int re = rcE[0], ce = rcE[1];
            if(re < rs){ sb.append(0).append('\n'); continue; }
            int k = re - rs;
            int d = ce - cs;
            if(d < 0 || d > k){ sb.append(0).append('\n'); continue; }
            sb.append(nCr(k,d)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

