const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
const MAXN = 50000;
const fact = new Array(MAXN+1);
const invFact = new Array(MAXN+1);
fact[0] = 1n;
for(let i=1;i<=MAXN;i++) fact[i] = fact[i-1] * BigInt(i) % MOD;
function modPow(a,e){let r=1n;let base=a%MOD;let exp=BigInt(e);while(exp>0n){if(exp&1n) r=r*base%MOD;base=base*base%MOD;exp>>=1n;}return r;}
invFact[MAXN] = modPow(fact[MAXN], MOD-2n);
for(let i=MAXN;i>0;i--) invFact[i-1] = invFact[i] * BigInt(i) % MOD;
function nCr(n,r){if(r<0||r>n) return 0n;return fact[n]*invFact[r]%MOD*invFact[n-r]%MOD;}
function rowCol(x){ // x is Number (<=1e9)
  const r = Math.ceil((Math.sqrt(8*x+1)-1)/2);
  const prev = r*(r-1)/2;
  const c = x - prev;
  return [r,c];
}
let out = [];
for(let t=0;t<T;t++){
  const s = Number(input[idx++]);
  const e = Number(input[idx++]);
  const [rs,cs] = rowCol(s);
  const [re,ce] = rowCol(e);
  if(re < rs){ out.push('0'); continue; }
  const k = re - rs;
  const d = ce - cs;
  if(d < 0 || d > k){ out.push('0'); continue; }
  out.push(String(nCr(k,d)));
}
